        }, 0);
      })) || 1;
      var barW = (width - 2 * pad) / rows.length * 0.55;
      var gap = (width - 2 * pad - barW * rows.length) / Math.max(rows.length - 1, 1);
      var svg = svgElement('svg', { viewBox: '0 0 ' + width + ' ' + height, class: 'chart-stacked-bar__svg' });

