      clear(plot);
      var flat = values.reduce(function (all, row) { return all.concat(row); }, []).map(Number);
      var vmax = Math.max.apply(null, flat);
      var vmin = Math.min.apply(null, flat);
      var span = vmax - vmin || 1;
